function createGenesis(GenesisCreationParams memory gParams) external returns (address) {
    require(
        IERC20(params.virtualToken).transferFrom(msg.sender, params.feeAddr, params.feeAmt),
        "transfer createGenesis fee failed"
    );

    gParams.endTime = gParams.startTime + params.duration;

    genesisID++;
    address addr = GenesisLib.validateAndDeploy(
        genesisID,
        address(this),
        gParams,
        params.tbaSalt,
        params.tbaImpl,
        params.votePeriod,
        params.threshold,
        params.agentFactory,
        params.virtualToken,
        params.reserve,
        params.maxContribution,
        params.agentTokenTotalSupply,
        params.agentTokenLpSupply
    );

    // Grant BONDING_ROLE of ato the new Genesis contract
    bytes32 BONDING_ROLE = AgentFactoryV3(params.agentFactory).BONDING_ROLE();
    AgentFactoryV3(params.agentFactory).grantRole(BONDING_ROLE, address(addr));

    genesisContracts[genesisID] = addr;
    emit GenesisCreated(genesisID, addr);
    return addr;
}
